alter table "public"."surveys" enable row level security;

CREATE UNIQUE INDEX survey_evidences_pkey ON public.survey_evidences USING btree (id);

CREATE UNIQUE INDEX surveys_pkey ON public.surveys USING btree (id);

alter table "public"."survey_evidences" add constraint "survey_evidences_pkey" PRIMARY KEY using index "survey_evidences_pkey";

alter table "public"."surveys" add constraint "surveys_pkey" PRIMARY KEY using index "surveys_pkey";

alter table "public"."survey_evidences" add constraint "survey_evidences_survey_id_fkey" FOREIGN KEY (survey_id) REFERENCES public.surveys(id) ON DELETE CASCADE not valid;

alter table "public"."survey_evidences" validate constraint "survey_evidences_survey_id_fkey";

alter table "public"."surveys" add constraint "surveys_user_id_fkey" FOREIGN KEY (user_id) REFERENCES auth.users(id) not valid;

alter table "public"."surveys" validate constraint "surveys_user_id_fkey";

set check_function_bodies = off;

CREATE OR REPLACE FUNCTION public.update_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN NEW.updated_at = NOW(); RETURN NEW; END;
$function$
;

