  create policy "Enable delete for all users"
  on "public"."survey_evidences"
  as permissive
  for delete
  to public
using (true);



  create policy "Enable insert for authenticated users only"
  on "public"."survey_evidences"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Enable read access for all users"
  on "public"."survey_evidences"
  as permissive
  for select
  to public
using (true);



  create policy "Enable delete for users based on user_id"
  on "public"."surveys"
  as permissive
  for delete
  to public
using ((( SELECT auth.uid() AS uid) = user_id));



  create policy "Enable insert for users based on user_id"
  on "public"."surveys"
  as permissive
  for insert
  to public
with check ((( SELECT auth.uid() AS uid) = user_id));



  create policy "Enable read access for all users"
  on "public"."surveys"
  as permissive
  for select
  to public
using (true);



  create policy "Policy with table joins"
  on "public"."surveys"
  as permissive
  for update
  to public
using (true);


CREATE TRIGGER trg_surveys_updated_at BEFORE UPDATE ON public.surveys FOR EACH ROW EXECUTE FUNCTION public.update_updated_at();

drop trigger if exists "protect_buckets_delete" on "storage"."buckets";

drop trigger if exists "protect_objects_delete" on "storage"."objects";


  create policy "Authenticated users can upload evidence files"
  on "storage"."objects"
  as permissive
  for insert
  to authenticated
with check ((bucket_id = 'evidences'::text));



  create policy "Public can view evidence files"
  on "storage"."objects"
  as permissive
  for select
  to public
using ((bucket_id = 'evidences'::text));




